import '@testing-library/jest-dom';
// This file was generated by an AI agent. Do not edit directly.
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { MediaControl, type MediaControlProps } from './MediaControl';

const playingTintClass = '[&_[data-slot="_icon"]]:text-color-content-brand';

const getIconEl = (): HTMLElement | null =>
  document.querySelector('[data-slot="_icon"]');

const renderMediaControl = (props?: Partial<MediaControlProps>) => render(<MediaControl {...props} />);

describe('MediaControl', () => {
  it('renders a button with the icon slot', () => {
    renderMediaControl();
    expect(getIconEl()).not.toBeNull();
  });

  it('applies the paused aria label by default', () => {
    renderMediaControl();
    expect(screen.getByRole('button')).toHaveAttribute('aria-label', 'Play media');
  });

  it('renders the play icon when paused', () => {
    renderMediaControl();
    const icon = getIconEl();
    expect(icon?.getAttribute('data-icon')).toBe('play');
  });

  it('switches to the pause icon after clicking once', async () => {
    const user = userEvent.setup();
    renderMediaControl();
    const button = screen.getByRole('button');

    await user.click(button);

    const icon = getIconEl();
    expect(icon?.getAttribute('data-icon')).toBe('pause');
  });

  it('respects defaultState="playing" on first render', () => {
    renderMediaControl({ defaultState: 'playing' });
    const button = screen.getByRole('button');
    const icon = getIconEl();
    expect({
      label: button.getAttribute('aria-label'),
      icon: icon?.getAttribute('data-icon')
    }).toEqual({ label: 'Pause media', icon: 'pause' });
  });

  it('updates the aria label when the control enters playing state', async () => {
    const user = userEvent.setup();
    renderMediaControl();
    const button = screen.getByRole('button');

    await user.click(button);

    expect(button).toHaveAttribute('aria-label', 'Pause media');
  });

  it('emits callbacks in order for playing then paused transitions', async () => {
    const calls: string[] = [];
    const user = userEvent.setup();
    renderMediaControl({
      onStateChange: next => {
        calls.push(`state:${next}`);
      },
      onPlay: () => {
        calls.push('play');
      },
      onPause: () => {
        calls.push('pause');
      }
    });
    const button = screen.getByRole('button');

    await user.click(button);
    await user.click(button);

    expect(calls).toEqual(['state:playing', 'play', 'state:paused', 'pause']);
  });

  it('does not toggle or emit callbacks when onClick prevents default', async () => {
    const calls: string[] = [];
    const user = userEvent.setup();
    renderMediaControl({
      onClick: event => event.preventDefault(),
      onStateChange: next => {
        calls.push(`state:${next}`);
      },
      onPlay: () => {
        calls.push('play');
      },
      onPause: () => {
        calls.push('pause');
      }
    });
    const button = screen.getByRole('button');
    const before = getIconEl()?.getAttribute('data-icon') ?? null;

    await user.click(button);

    const after = getIconEl()?.getAttribute('data-icon') ?? null;
    expect(after).toBe(before);
    expect(calls).toEqual([]);
  });

  it('does not toggle visuals when controlled without external state change', async () => {
    const user = userEvent.setup();
    renderMediaControl({ state: 'paused', onStateChange: () => {} });
    const button = screen.getByRole('button');

    await user.click(button);

    const icon = getIconEl();
    expect(icon?.getAttribute('data-icon')).toBe('play');
  });

  it('reflects controlled prop updates', () => {
    const { rerender } = renderMediaControl({ state: 'paused', onStateChange: () => {} });
    rerender(<MediaControl state="playing" onStateChange={() => {}} />);
    const icon = getIconEl();
    expect(icon?.getAttribute('data-icon')).toBe('pause');
  });

  it('uses caller-provided labels when supplied', () => {
    renderMediaControl({ ariaLabelPlay: 'Resume audio' });
    const button = screen.getByRole('button');
    expect(button).toHaveAttribute('aria-label', 'Resume audio');
  });

  it('falls back to non-empty defaults when custom labels are empty strings', async () => {
    const user = userEvent.setup();
    renderMediaControl({ ariaLabelPlay: '   ', ariaLabelPause: ' ' });
    const button = screen.getByRole('button');
    const labels: Array<string | null> = [];
    labels.push(button.getAttribute('aria-label'));
    await user.click(button);
    labels.push(button.getAttribute('aria-label'));
    expect(labels).toEqual(['Play media', 'Pause media']);
  });

  it('toggles via keyboard Space key (uncontrolled)', async () => {
    const user = userEvent.setup();
    renderMediaControl();

    await user.tab();
    const button = screen.getByRole('button');
    expect(button).toHaveFocus();
    const iconStates: Array<string | null> = [];
    await user.keyboard('[Space]');
    iconStates.push(getIconEl()?.getAttribute('data-icon') ?? null);
    await user.keyboard('[Space]');
    iconStates.push(getIconEl()?.getAttribute('data-icon') ?? null);
    expect(iconStates).toEqual(['pause', 'play']);
  });

  it('exposes data-state="paused" by default (uncontrolled)', () => {
    renderMediaControl();
    const button = screen.getByRole('button');
    expect(button.getAttribute('data-state')).toBe('paused');
  });

  it('exposes data-state from controlled prop', () => {
    const { rerender } = renderMediaControl({ state: 'paused' });
    let button = screen.getByRole('button');
    expect(button.getAttribute('data-state')).toBe('paused');
    rerender(<MediaControl state="playing" />);
    button = screen.getByRole('button');
    expect(button.getAttribute('data-state')).toBe('playing');
  });

  it('adds the playing tint class when state is playing', () => {
    renderMediaControl({ state: 'playing' });
    const button = screen.getByRole('button');
    expect(button.className.includes(playingTintClass)).toBe(true);
  });

  it('omits the playing tint class when paused', () => {
    renderMediaControl();
    const button = screen.getByRole('button');
    expect(button.className.includes(playingTintClass)).toBe(false);
  });

  it('shows the focus-visible ring after keyboard focus', async () => {
    const user = userEvent.setup();
    renderMediaControl();

    await user.tab();

    const button = screen.getByRole('button');
    const focusState = {
      isFocused: document.activeElement === button,
      hasFocusClass: button.className.includes('focus-visible:ring-comp-border-focus-ring')
    };
    expect(focusState).toEqual({ isFocused: true, hasFocusClass: true });
  });
});
